  1→import type { MittwaldCliToolHandler } from '../../../../types/mittwald/conversation.js';
  2→import { formatToolResponse } from '../../../../utils/format-tool-response.js';
  3→import { createVirtualHost, LibraryError } from '@mittwald-mcp/cli-core';
  4→import { sessionManager } from '../../../../server/session-manager.js';
  5→import { getCurrentSessionId } from '../../../../utils/execution-context.js';
  6→import { logger } from '../../../../utils/logger.js';
  7→
  8→interface MittwaldDomainVirtualhostCreateArgs {
  9→  hostname: string;
 10→  projectId?: string;
 11→  quiet?: boolean;
 12→  pathToApp?: string[];
 13→  pathToUrl?: string[];
 14→  pathToContainer?: string[];
 15→}
 16→
 17→function parsePathMappings(args: MittwaldDomainVirtualhostCreateArgs): any[] {
 18→  const paths: any[] = [];
 19→
 20→  // Parse path-to-app mappings (format: "path=/,appInstallationId=123")
 21→  if (args.pathToApp) {
 22→    for (const mapping of args.pathToApp) {
 23→      const parts = mapping.split(',');
 24→      const pathPart = parts.find(p => p.startsWith('path='));
 25→      const appPart = parts.find(p => p.startsWith('appInstallationId='));
 26→      if (pathPart && appPart) {
 27→        paths.push({
 28→          path: pathPart.split('=')[1],
 29→          target: { appInstallationId: appPart.split('=')[1] }
 30→        });
 31→      }
 32→    }
 33→  }
 34→
 35→  // Parse path-to-url mappings (format: "path=/,url=https://example.com")
 36→  if (args.pathToUrl) {
 37→    for (const mapping of args.pathToUrl) {
 38→      const parts = mapping.split(',');
 39→      const pathPart = parts.find(p => p.startsWith('path='));
 40→      const urlPart = parts.find(p => p.startsWith('url='));
 41→      if (pathPart && urlPart) {
 42→        paths.push({
 43→          path: pathPart.split('=')[1],
 44→          target: { url: urlPart.split('=')[1] }
 45→        });
 46→      }
 47→    }
 48→  }
 49→
 50→  // Parse path-to-container mappings (format: "path=/,containerId=123")
 51→  if (args.pathToContainer) {
 52→    for (const mapping of args.pathToContainer) {
 53→      const parts = mapping.split(',');
 54→      const pathPart = parts.find(p => p.startsWith('path='));
 55→      const containerPart = parts.find(p => p.startsWith('containerId='));
 56→      if (pathPart && containerPart) {
 57→        paths.push({
 58→          path: pathPart.split('=')[1],
 59→          target: { containerId: containerPart.split('=')[1] }
 60→        });
 61→      }
 62→    }
 63→  }
 64→
 65→  return paths;
 66→}
 67→
 68→export const handleDomainVirtualhostCreateCli: MittwaldCliToolHandler<MittwaldDomainVirtualhostCreateArgs> = async (args, sessionId) => {
 69→  if (!args.hostname) {
 70→    return formatToolResponse('error', 'Hostname is required.');
 71→  }
 72→
 73→  const effectiveSessionId = sessionId || getCurrentSessionId();
 74→
 75→  if (!effectiveSessionId) {
 76→    return formatToolResponse('error', 'Session ID required');
 77→  }
 78→
 79→  const session = await sessionManager.getSession(effectiveSessionId);
 80→  if (!session?.mittwaldAccessToken) {
 81→    return formatToolResponse('error', 'No Mittwald access token found in session. Please authenticate first.');
 82→  }
 83→
 84→  const paths = parsePathMappings(args);
 85→
 86→  try {
 87→    const result = await createVirtualHost({
 88→      hostname: args.hostname,
 89→      paths: paths,
 90→      projectId: args.projectId || '',
 91→      apiToken: session.mittwaldAccessToken,
 92→    });
 93→
 94→    const ingressId = result.data?.id || result.data?.ingressId;
 95→
 96→    const resultData = {
 97→      id: ingressId,
 98→      hostname: args.hostname,
 99→      ...(args.pathToApp && { pathToApp: args.pathToApp }),
100→      ...(args.pathToUrl && { pathToUrl: args.pathToUrl }),
101→      ...(args.pathToContainer && { pathToContainer: args.pathToContainer }),
102→    };
103→
104→    return formatToolResponse(
105→      'success',
106→      args.quiet ? ingressId : `Successfully created virtual host '${args.hostname}' with ID ${ingressId}`,
107→      resultData,
108→      {
109→        durationMs: result.durationMs,
110→      }
111→    );
112→  } catch (error) {
113→    if (error instanceof LibraryError) {
114→      return formatToolResponse('error', error.message, {
115→        code: error.code,
116→        details: error.details,
117→      });
118→    }
119→
120→    logger.error('[WP06] Unexpected error in virtualhost create handler', { error });
121→    return formatToolResponse('error', `Failed to create virtual host: ${error instanceof Error ? error.message : String(error)}`);
122→  }
123→};
