 11→// Generic API call wrapper
 12→async function executeApiCall<T = any>(
 13→  apiToken: string,
 14→  apiCall: (client: MittwaldAPIV2Client) => Promise<any>,
 15→  expectedStatus: number = 200
 16→): Promise<LibraryResult<T>> {
 17→  const startTime = performance.now();
 18→
 19→  try {
 20→    const client = MittwaldAPIV2Client.newWithToken(apiToken);
 21→    const response = await apiCall(client);
 22→    assertStatus(response, expectedStatus);
 23→
 24→    return {
 25→      data: response.data,
 26→      status: response.status,
 27→      durationMs: performance.now() - startTime,
 28→    };
 29→  } catch (error) {
 30→    throw new LibraryError(
 31→      error instanceof Error ? error.message : 'Unknown error',
 32→      (error as any).status || 500,
 33→      { originalError: error, durationMs: performance.now() - startTime }
 34→    );
 35→  }
 36→}
